import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Edit3, Save, Plus, Trash2, MapPin, ShieldCheck, Coins, X } from 'lucide-react';

export default function Profile() {
  const [isEdit, setIsEdit] = useState(false);
  
  // Profile State
  const [profile, setProfile] = useState({
    name: "Arjun Das",
    location: "Kadavanthra, Kochi",
    tokens: 1450, // Matches Dashboard
    skills: ["Web Design", "Gardening", "Plumbing"]
  });

  const [newSkill, setNewSkill] = useState("");
  const [showSkillInput, setShowSkillInput] = useState(false);

  // Add a new skill
  const addSkill = () => {
    if (newSkill.trim() && !profile.skills.includes(newSkill)) {
      setProfile({ ...profile, skills: [...profile.skills, newSkill.trim()] });
      setNewSkill("");
      setShowSkillInput(false);
    }
  };

  // Remove a skill
  const removeSkill = (skillToRemove) => {
    setProfile({
      ...profile,
      skills: profile.skills.filter(s => s !== skillToRemove)
    });
  };

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="p-10 max-w-5xl mx-auto space-y-8">
      
      {/* Header Profile Card */}
      <div className="bg-white rounded-[40px] p-10 shadow-sm border border-slate-50 flex flex-col md:flex-row items-center gap-10">
        <div className="w-32 h-32 bg-teal-50 rounded-full flex items-center justify-center text-teal-600 text-4xl font-black border-4 border-white shadow-xl relative">
          {profile.name[0]}
          <div className="absolute -bottom-2 -right-2 bg-yellow-400 text-white p-2 rounded-xl shadow-lg">
            <Coins size={20} />
          </div>
        </div>

        <div className="flex-1 text-center md:text-left">
          {isEdit ? (
            <div className="space-y-3">
              <input 
                value={profile.name} 
                onChange={e => setProfile({...profile, name: e.target.value})} 
                className="text-3xl font-black text-slate-900 bg-slate-50 px-4 py-2 rounded-2xl outline-none ring-2 ring-teal-500 w-full"
                placeholder="Full Name"
              />
              <div className="flex items-center gap-2 bg-slate-50 px-4 py-2 rounded-2xl ring-2 ring-teal-500">
                <MapPin size={18} className="text-teal-600"/>
                <input 
                  value={profile.location} 
                  onChange={e => setProfile({...profile, location: e.target.value})} 
                  className="bg-transparent outline-none w-full font-bold text-slate-600"
                  placeholder="Location"
                />
              </div>
            </div>
          ) : (
            <>
              <h1 className="text-4xl font-black text-slate-900">{profile.name}</h1>
              <p className="text-slate-400 font-bold mt-2 flex items-center justify-center md:justify-start gap-2">
                <MapPin size={18} className="text-teal-600"/> {profile.location}
              </p>
              <div className="mt-4 inline-flex items-center gap-2 px-3 py-1 bg-teal-50 text-teal-600 rounded-full text-[10px] font-black uppercase tracking-widest">
                <ShieldCheck size={14} /> Verified Member
              </div>
            </>
          )}
        </div>

        <div className="flex flex-col gap-3">
          <div className="bg-slate-900 text-white px-8 py-4 rounded-[24px] text-center shadow-lg">
            <p className="text-[10px] font-black uppercase tracking-widest text-teal-400">Balance</p>
            <p className="text-2xl font-black">{profile.tokens} <span className="text-sm text-slate-400">WTK</span></p>
          </div>
          <button 
            onClick={() => setIsEdit(!isEdit)} 
            className={`flex items-center justify-center gap-2 px-8 py-4 rounded-2xl font-bold transition-all ${isEdit ? 'bg-teal-600 text-white shadow-teal-600/20 shadow-lg' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
          >
            {isEdit ? <><Save size={20}/> Save Changes</> : <><Edit3 size={20}/> Edit Profile</>}
          </button>
        </div>
      </div>

      {/* Skills Section */}
      <div className="bg-white rounded-[40px] p-10 border border-slate-50 shadow-sm">
        <div className="flex justify-between items-center mb-8">
          <h3 className="text-xl font-black text-slate-900">Skill Preferences</h3>
          {isEdit && (
            <button 
              onClick={() => setShowSkillInput(true)}
              className="flex items-center gap-2 text-teal-600 font-bold hover:bg-teal-50 px-4 py-2 rounded-xl transition-all"
            >
              <Plus size={18} /> Add Skill
            </button>
          )}
        </div>

        <div className="flex flex-wrap gap-3">
          {profile.skills.map(s => (
            <div key={s} className="px-6 py-3 bg-teal-50/50 border border-teal-100 text-teal-700 rounded-2xl font-bold text-sm flex items-center gap-3 group transition-all">
              {s} 
              {isEdit && (
                <Trash2 
                  size={14} 
                  className="cursor-pointer text-red-400 hover:text-red-600" 
                  onClick={() => removeSkill(s)}
                />
              )}
            </div>
          ))}
        </div>

        {/* New Skill Input Modal */}
        <AnimatePresence>
          {showSkillInput && (
            <motion.div 
              initial={{ opacity: 0, y: 10 }} 
              animate={{ opacity: 1, y: 0 }} 
              exit={{ opacity: 0, y: 10 }}
              className="mt-6 p-6 bg-slate-50 rounded-3xl border border-slate-200 flex gap-4 items-center"
            >
              <input 
                autoFocus
                value={newSkill}
                onChange={(e) => setNewSkill(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && addSkill()}
                placeholder="Type a new skill (e.g. Cooking)..." 
                className="flex-1 bg-white px-6 py-3 rounded-xl outline-none ring-2 ring-transparent focus:ring-teal-500 font-bold"
              />
              <button onClick={addSkill} className="bg-teal-600 text-white px-6 py-3 rounded-xl font-bold">Add</button>
              <button onClick={() => setShowSkillInput(false)} className="text-slate-400"><X size={24}/></button>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </motion.div>
  );
}
